public class SuperCall {
    static class Base {
        String greet(String name) { return "Hello, " + name; }
    }
    static class Formal extends Base {
        String greet(String name) { return super.greet(name) + "! How do you do?"; }
    }
    static class Casual extends Formal {
        String greet(String name) { return "Hey " + name + "!"; }
    }
    public static void main(String[] args) {
        Base b = new Formal();
        System.out.println(b.greet("Alice"));
        b = new Casual();
        System.out.println(b.greet("Bob"));
    }
}
